let lead;
try {
  lead = $('Calculate Final Combined Score').item.json;
} catch (e) {
  lead = $('Set Default Values').item.json;
}

const score = Number(lead.final_score ?? lead.intent_score) || 50;
const isFreemium = lead.is_freemium_domain;

let status = "PLG";
if (score >= 80 && !isFreemium) status = "Hot Lead";
else if (score >= 50 && !isFreemium) status = "Nurture";

const output = {
  name: lead.name,
  email: lead.email,
  original_message: lead.original_message,
  company_domain: lead.company_domain,
  company_name: lead.company_name === "None" ? null : lead.company_name,
  industry: lead.industry === "Unknown" ? null : lead.industry,
  employee_count: lead.employee_count || null,
  estimated_revenue: lead.estimated_revenue === "Unknown" ? null : lead.estimated_revenue,
  icp_fit_score: lead.icp_fit_score,
  text_intent_score: lead.text_intent_score,
  final_score: lead.final_score,
  intent_score: lead.intent_score,
  reasoning_summary: lead.reasoning_summary,
  status: status
};

return { json: output };

return $input.all().filter((item) => {
  const score = Number(item.json.final_score ?? item.json.intent_score) || 0;
  const isFreemium = item.json.is_freemium_domain === true;
  return score >= 75 && !isFreemium;
});

return $input.all().filter((item) => {
  const score = Number(item.json.final_score ?? item.json.intent_score) || 0;
  const isFreemium = item.json.is_freemium_domain === true;
  return score >= 50 && score < 75 && !isFreemium;
});

return $input.all().filter((item) => {
  const score = Number(item.json.final_score ?? item.json.intent_score) || 0;
  const isFreemium = item.json.is_freemium_domain === true;
  return score < 50 || isFreemium;
});

const item = $input.item;
const icpFitScore = Number(item.json.icp_fit_score) || 0;
const textIntentScore = Number(item.json.text_intent_score) || 0;
const finalScore = Math.round((icpFitScore * 0.5) + (textIntentScore * 0.5));

item.json.final_score = Math.max(0, Math.min(100, finalScore));
item.json.intent_score = item.json.final_score;
item.json.reasoning_summary = `ICP fit ${icpFitScore}/100 + text intent ${textIntentScore}/100. ${item.json.intent_reasoning || ''}`.trim();

return item;

let text_intent_score = 50;
let intent_reasoning = "LLM unavailable; defaulted text intent score to neutral.";
let llm_status = "defaulted";
let llm_error = null;

const clampScore = (value) => Math.max(1, Math.min(100, Math.round(Number(value))));

try {
  const responseBody = $input.item.json;

  if (responseBody?.error) {
    const status = responseBody.error.status ?? responseBody.error.code ?? "unknown";
    const message = responseBody.error.message || "Gemini request failed.";
    llm_error = `Gemini request failed (${status}): ${message}`;
    intent_reasoning = status === 503
      ? "Gemini was temporarily unavailable due to high demand; defaulted text intent score to neutral."
      : "Gemini request failed; defaulted text intent score to neutral.";
  } else {
    const text = responseBody?.candidates?.[0]?.content?.parts?.[0]?.text;
    if (!text || typeof text !== 'string') {
      throw new Error('Gemini response did not include candidate text.');
    }

    const parsed = JSON.parse(text);
    const parsedScore = Number(parsed.text_intent_score);

    if (Number.isFinite(parsedScore)) {
      text_intent_score = clampScore(parsedScore);
      llm_status = "scored";
    } else {
      throw new Error('Gemini response did not include a numeric text_intent_score.');
    }

    if (typeof parsed.intent_reasoning === 'string' && parsed.intent_reasoning.trim()) {
      intent_reasoning = parsed.intent_reasoning.trim();
    } else {
      intent_reasoning = "Gemini returned a score without reasoning.";
    }
  }
} catch (e) {
  llm_error = e.message || String(e);
  intent_reasoning = "LLM output validation failed; defaulted text intent score to neutral.";
}

const companyData = $("Calculate ICP Fit Score").first().json;
const leadData = $("Parse Email Domain").first().json;

$input.item.json = {
  name: leadData.name,
  email: leadData.email,
  original_message: leadData.original_message,
  company_domain: leadData.company_domain,
  company_name: companyData.company_name,
  industry: companyData.industry,
  employee_count: companyData.employee_count,
  estimated_revenue: companyData.estimated_revenue,
  current_technologies: companyData.current_technologies,
  icp_fit_score: companyData.icp_fit_score,
  text_intent_score,
  intent_reasoning,
  llm_status,
  llm_error
};

return $input.item;

