const item = $input.item;
const employees = Number(item.json.employee_count) || 0;
const industry = String(item.json.industry || '').toLowerCase();

let icpFitScore = 0;
if (employees > 1000) {
  icpFitScore += 40;
} else if (employees >= 100 && employees <= 999) {
  icpFitScore += 20;
}

if (industry.includes('software') || industry.includes('technology')) {
  icpFitScore += 20;
}

item.json.icp_fit_score = Math.max(0, Math.min(100, icpFitScore));
return item;
